# Skeptic review S50-T1-A-E2: verify PASS/CONTINUE only on taught contract
def assess(record: dict) -> str:
    required = {'tasks', 'rubric_levels', 'holdout', 'slices', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if sum(record["slices"].values()) != record["tasks"] or record["holdout"] != 0 else "REBUILD_EVAL_DATASET"

valid = {'case_id': 'CASO-ICA-050-1A', 'tasks': 40, 'slices': {'normal': 25, 'edge': 10, 'adversarial': 5}, 'rubric_levels': {0, 1, 2, 3}, 'holdout': 10}
invalid = {'case_id': 'CASO-ICA-050-1A', 'tasks': 40, 'slices': {'normal': 25, 'edge': 10, 'adversarial': 5}, 'rubric_levels': {0, 1, 2, 3}, 'holdout': 0}
incomplete = {**valid}
incomplete.pop('holdout', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

